package com.example.oidcclient.security;

import com.example.oidcclient.config.OidcProperties;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.security.SecureRandom;
import java.util.Base64;

public class OidcAuthFilter extends OncePerRequestFilter {

    private final OidcProperties props;
    private final SecureRandom random = new SecureRandom();

    public OidcAuthFilter(OidcProperties props) {
        this.props = props;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
        if (request.getRequestURI() == null || !request.getRequestURI().startsWith(request.getContextPath() + "/protected")) {
            filterChain.doFilter(request, response);
            return;
        }

        String sessionId = SessionCookies.readSessionId(request, props.getSessionCookieName());
        if (sessionId != null) {
            filterChain.doFilter(request, response);
            return;
        }

        String state = randomUrlSafe(32);
        String nonce = randomUrlSafe(32);
        request.getSession(true).setAttribute("OIDC_STATE", state);
        request.getSession(true).setAttribute("OIDC_NONCE", nonce);
        request.getSession(true).setAttribute("OIDC_RETURN_TO", request.getRequestURI() + (request.getQueryString() != null ? "?" + request.getQueryString() : ""));

        String authUrl = props.getAuthorizationEndpoint()
                + "?response_type=code"
                + "&client_id=" + urlEnc(props.getClientId())
                + "&redirect_uri=" + urlEnc(props.getRedirectUri())
                + "&scope=" + urlEnc(String.join(" ", props.getScopes()))
                + "&state=" + urlEnc(state)
                + "&nonce=" + urlEnc(nonce);

        response.setStatus(302);
        response.setHeader("Location", authUrl);
    }

    private String randomUrlSafe(int bytes) {
        byte[] b = new byte[bytes];
        random.nextBytes(b);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(b);
    }

    private String urlEnc(String s) {
        return URLEncoder.encode(s, StandardCharsets.UTF_8);
    }
}

package com.example.oidcclient.security;

import com.example.oidcclient.config.OidcProperties;
import com.example.oidcclient.model.OidcSession;
import com.example.oidcclient.model.OidcTokenResponse;
import com.example.oidcclient.service.OidcClient;
import com.example.oidcclient.service.OidcSessionService;
import com.example.oidcclient.service.OidcTokensValidator;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;

public class OidcCallbackFilter extends OncePerRequestFilter {

    private final OidcClient client;
    private final OidcSessionService sessionService;
    private final OidcProperties props;

    public OidcCallbackFilter(OidcClient client, OidcSessionService sessionService, OidcProperties props) {
        this.client = client;
        this.sessionService = sessionService;
        this.props = props;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
        String path = request.getRequestURI();
        String callbackPath = request.getContextPath() + props.getCallbackPath();
        if (!path.equals(callbackPath)) {
            filterChain.doFilter(request, response);
            return;
        }

        String code = request.getParameter("code");
        String state = request.getParameter("state");
        String error = request.getParameter("error");

        if (error != null) {
            response.setStatus(401);
            response.getWriter().write("OIDC error: " + error);
            return;
        }

        String expectedState = (String) request.getSession(true).getAttribute("OIDC_STATE");
        String nonce = (String) request.getSession(true).getAttribute("OIDC_NONCE");
        if (expectedState == null || !expectedState.equals(state)) {
            response.setStatus(401);
            response.getWriter().write("Invalid OIDC state");
            return;
        }
        if (code == null || code.isBlank()) {
            response.setStatus(400);
            response.getWriter().write("Missing authorization code");
            return;
        }

        OidcTokenResponse tokenResponse = client.exchangeCodeForTokens(code);
        OidcTokensValidator validator = new OidcTokensValidator(props);
        var idClaims = validator.parseAndValidateIdToken(tokenResponse.getIdToken(), nonce);

        OidcSession session = sessionService.createSession(idClaims, tokenResponse);
        SessionCookies.writeSessionCookie(response, props, session.getSessionId());

        String returnTo = (String) request.getSession(true).getAttribute("OIDC_RETURN_TO");
        if (returnTo == null || returnTo.isBlank()) returnTo = props.getPostLoginRedirect();

        response.setStatus(302);
        response.setHeader("Location", returnTo);
    }
}

package com.example.oidcclient.security;

import com.example.oidcclient.config.OidcProperties;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;

public final class SessionCookies {

    private SessionCookies() {}

    public static String readSessionId(HttpServletRequest request, String cookieName) {
        if (request.getCookies() == null) return null;
        for (var c : request.getCookies()) {
            if (cookieName.equals(c.getName())) return c.getValue();
        }
        return null;
    }

    public static void writeSessionCookie(HttpServletResponse response, OidcProperties props, String sessionId) {
        StringBuilder sb = new StringBuilder();
        sb.append(props.getSessionCookieName()).append("=").append(sessionId).append("; Path=/; HttpOnly; Max-Age=").append(props.getSessionMaxAgeSeconds());
        if (props.isSessionCookieSecure()) sb.append("; Secure");
        if (props.getSessionCookieSameSite() != null && !props.getSessionCookieSameSite().isBlank()) {
            sb.append("; SameSite=").append(props.getSessionCookieSameSite());
        }
        response.addHeader("Set-Cookie", sb.toString());
    }

    public static void clearSessionCookie(HttpServletResponse response, OidcProperties props) {
        StringBuilder sb = new StringBuilder();
        sb.append(props.getSessionCookieName()).append("=; Path=/; HttpOnly; Max-Age=0");
        if (props.isSessionCookieSecure()) sb.append("; Secure");
        if (props.getSessionCookieSameSite() != null && !props.getSessionCookieSameSite().isBlank()) {
            sb.append("; SameSite=").append(props.getSessionCookieSameSite());
        }
        response.addHeader("Set-Cookie", sb.toString());
    }
}

