package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProperties;
import com.example.oidcclient.model.OidcTokenResponse;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.http.*;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.nio.charset.StandardCharsets;
import java.util.Base64;

public class OidcClient {

    private final OidcProperties props;
    private final RestTemplate restTemplate;
    private final ObjectMapper objectMapper;

    public OidcClient(OidcProperties props) {
        this.props = props;
        this.restTemplate = new RestTemplate();
        this.objectMapper = new ObjectMapper();
    }

    public OidcTokenResponse exchangeCodeForTokens(String code) {
        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));

        String basic = props.getClientId() + ":" + props.getClientSecret();
        String basicAuth = Base64.getEncoder().encodeToString(basic.getBytes(StandardCharsets.UTF_8));
        headers.set("Authorization", "Basic " + basicAuth);

        MultiValueMap<String, String> form = new LinkedMultiValueMap<>();
        form.add("grant_type", "authorization_code");
        form.add("code", code);
        form.add("redirect_uri", props.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> entity = new HttpEntity<>(form, headers);

        ResponseEntity<String> resp = restTemplate.exchange(props.getTokenEndpoint(), HttpMethod.POST, entity, String.class);
        if (!resp.getStatusCode().is2xxSuccessful() || resp.getBody() == null) {
            throw new IllegalStateException("Token endpoint error: " + resp.getStatusCode());
        }
        try {
            return objectMapper.readValue(resp.getBody(), OidcTokenResponse.class);
        } catch (Exception e) {
            throw new IllegalStateException("Failed to parse token response", e);
        }
    }

    public String fetchUserInfo(String accessToken) {
        HttpHeaders headers = new HttpHeaders();
        headers.set("Authorization", "Bearer " + accessToken);
        headers.setAccept(java.util.List.of(MediaType.APPLICATION_JSON));
        HttpEntity<Void> entity = new HttpEntity<>(headers);
        ResponseEntity<String> resp = restTemplate.exchange(props.getUserinfoEndpoint(), HttpMethod.GET, entity, String.class);
        if (!resp.getStatusCode().is2xxSuccessful()) {
            throw new IllegalStateException("UserInfo endpoint error: " + resp.getStatusCode());
        }
        return resp.getBody();
    }
}

package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProperties;
import com.fasterxml.jackson.core.type.TypeReference;
import com.fasterxml.jackson.databind.ObjectMapper;

import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.Base64;
import java.util.List;
import java.util.Map;

public class OidcTokensValidator {

    private final OidcProperties props;
    private final ObjectMapper mapper = new ObjectMapper();

    public OidcTokensValidator(OidcProperties props) {
        this.props = props;
    }

    public Map<String, Object> parseAndValidateIdToken(String idToken, String expectedNonce) {
        if (idToken == null || idToken.isBlank()) throw new IllegalArgumentException("Missing id_token");
        String[] parts = idToken.split("\\.");
        if (parts.length != 3) throw new IllegalArgumentException("Invalid JWT");

        Map<String, Object> header = json(parts[0]);
        Map<String, Object> claims = json(parts[1]);
        String alg = (String) header.get("alg");
        if (alg == null) throw new IllegalArgumentException("Missing alg");
        if (!List.of("HS256", "none").contains(alg)) throw new IllegalArgumentException("Unsupported alg: " + alg);

        if ("HS256".equals(alg)) {
            String signingInput = parts[0] + "." + parts[1];
            String expectedSig = base64Url(hmacSha256(signingInput.getBytes(StandardCharsets.UTF_8), props.getClientSecret().getBytes(StandardCharsets.UTF_8)));
            if (!constantTimeEquals(expectedSig, parts[2])) {
                throw new IllegalArgumentException("Invalid id_token signature");
            }
        } else {
            throw new IllegalArgumentException("alg=none is not allowed");
        }

        if (props.isValidateIssuer()) {
            String iss = (String) claims.get("iss");
            if (iss == null || !iss.equals(props.getIssuer())) throw new IllegalArgumentException("Invalid issuer");
        }

        if (props.isValidateAudience()) {
            Object aud = claims.get("aud");
            if (aud instanceof String s) {
                if (!props.getClientId().equals(s)) throw new IllegalArgumentException("Invalid audience");
            } else if (aud instanceof List<?> l) {
                boolean ok = l.stream().anyMatch(x -> props.getClientId().equals(String.valueOf(x)));
                if (!ok) throw new IllegalArgumentException("Invalid audience");
            } else {
                throw new IllegalArgumentException("Invalid aud claim");
            }
        }

        if (expectedNonce != null) {
            String nonce = (String) claims.get("nonce");
            if (nonce == null || !nonce.equals(expectedNonce)) throw new IllegalArgumentException("Invalid nonce");
        }

        long now = Instant.now().getEpochSecond();
        long skew = props.getClockSkewSeconds();

        Number exp = (Number) claims.get("exp");
        if (exp == null) throw new IllegalArgumentException("Missing exp");
        if (now - skew >= exp.longValue()) throw new IllegalArgumentException("Token expired");

        Number iat = (Number) claims.get("iat");
        if (iat != null && iat.longValue() > now + skew) throw new IllegalArgumentException("Invalid iat");

        String sub = (String) claims.get("sub");
        if (sub == null || sub.isBlank()) throw new IllegalArgumentException("Missing sub");

        return claims;
    }

    private Map<String, Object> json(String b64url) {
        try {
            byte[] bytes = Base64.getUrlDecoder().decode(b64url);
            return mapper.readValue(bytes, new TypeReference<Map<String, Object>>() {});
        } catch (Exception e) {
            throw new IllegalArgumentException("Invalid JWT JSON", e);
        }
    }

    private byte[] hmacSha256(byte[] data, byte[] key) {
        try {
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(new SecretKeySpec(key, "HmacSHA256"));
            return mac.doFinal(data);
        } catch (Exception e) {
            throw new IllegalStateException(e);
        }
    }

    private String base64Url(byte[] bytes) {
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private boolean constantTimeEquals(String a, String b) {
        if (a == null || b == null) return false;
        if (a.length() != b.length()) return false;
        int r = 0;
        for (int i = 0; i < a.length(); i++) r |= a.charAt(i) ^ b.charAt(i);
        return r == 0;
    }
}

package com.example.oidcclient.service;

import com.example.oidcclient.config.OidcProperties;
import com.example.oidcclient.model.OidcSession;
import com.example.oidcclient.model.OidcTokenResponse;
import com.example.oidcclient.security.SessionCookies;
import jakarta.annotation.PostConstruct;
import jakarta.servlet.ServletContext;
import jakarta.servlet.http.HttpServletRequest;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.time.Instant;
import java.util.Base64;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class OidcSessionService {

    private final OidcProperties props;
    private final Map<String, OidcSession> sessions = new ConcurrentHashMap<>();
    private final SecureRandom random = new SecureRandom();

    private final ServletContext servletContext;

    public OidcSessionService(OidcProperties props, ServletContext servletContext) {
        this.props = props;
        this.servletContext = servletContext;
    }

    public OidcSessionService(OidcProperties props) {
        this.props = props;
        this.servletContext = null;
    }

    @PostConstruct
    public void registerInServletContext() {
        if (servletContext != null) {
            servletContext.setAttribute("OIDC_SESSION_SERVICE", this);
        }
    }

    public OidcSession createSession(Map<String, Object> idTokenClaims, OidcTokenResponse tokenResponse) {
        String sessionId = newSessionId();
        String sub = (String) idTokenClaims.get("sub");
        String iss = (String) idTokenClaims.get("iss");
        String email = (String) idTokenClaims.get("email");
        String name = (String) idTokenClaims.get("name");

        OidcSession session = new OidcSession(
                sessionId,
                sub,
                iss,
                email,
                name,
                Instant.now(),
                idTokenClaims,
                tokenResponse.getAccessToken(),
                tokenResponse.getRefreshToken()
        );
        sessions.put(sessionId, session);
        return session;
    }

    public OidcSession getSession(String sessionId) {
        if (sessionId == null) return null;
        return sessions.get(sessionId);
    }

    public OidcSession getSessionByRequest(HttpServletRequest request) {
        String sid = SessionCookies.readSessionId(request, props.getSessionCookieName());
        return getSession(sid);
    }

    public void invalidate(String sessionId) {
        if (sessionId != null) sessions.remove(sessionId);
    }

    private String newSessionId() {
        byte[] b = new byte[32];
        random.nextBytes(b);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(b);
    }
}

