import jakarta.servlet.http.HttpServletResponse;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.LinkedHashMap;
import java.util.Map;

@RestController
public class DemoController {

    private final OidcSessionService sessionService;
    private final OidcProperties props;

    public DemoController(OidcSessionService sessionService, OidcProperties props) {
        this.sessionService = sessionService;
        this.props = props;
    }

    @GetMapping("/")
    public String home() {
        return "OK. Visit /protected to trigger OIDC login.";
    }

    @GetMapping("/protected")
    public Map<String, Object> protectedEndpoint(HttpServletRequest request) {
        OidcSession session = sessionService.getSessionByRequest(request);
        Map<String, Object> out = new LinkedHashMap<>();
        out.put("authenticated", session != null);
        if (session != null) {
            out.put("sub", session.getSubject());
            out.put("email", session.getEmail());
            out.put("name", session.getName());
            out.put("issuer", session.getIssuer());
            out.put("claims", session.getIdTokenClaims());
        }
        return out;
    }

    @GetMapping("/logout")
    public String logout(HttpServletRequest request, HttpServletResponse response) {
        String sid = com.example.oidcclient.security.SessionCookies.readSessionId(request, props.getSessionCookieName());
        sessionService.invalidate(sid);
        SessionCookies.clearSessionCookie(response, props);
        return "Logged out";
    }
}

